def haversine_distance(coord1: Tuple[float, float], coord2: Tuple[float, float]) -> float:
    """Calculate the haversine distance in km between two (lat, lon) points."""
    lat1, lon1 = math.radians(coord1[0]), math.radians(coord1[1])
    lat2, lon2 = math.radians(coord2[0]), math.radians(coord2[1])
    dlat = lat2 - lat1
    dlon = lon2 - lon1
    a = math.sin(dlat / 2) ** 2 + math.cos(lat1) * math.cos(lat2) * math.sin(dlon / 2) ** 2
    c = 2 * math.asin(math.sqrt(a))
    return 6371.0 * c


def get_traffic_factor(time_min: int) -> float:
    """
    Return a traffic multiplier based on time of day (minutes from midnight).
    Peak hours: 7-10 AM and 5-8 PM
    """
    if 420 <= time_min <= 600:
        return 1.5   # Morning rush
    elif 1020 <= time_min <= 1200:
        return 1.6   # Evening rush
    elif 600 < time_min < 1020:
        return 1.1   # Mid-day
    elif time_min >= 1320 or time_min < 300:
        return 0.8   # Late night
    else:
        return 1.0   # Normal


def get_next_departure(
    mode: str,
    station: str,
    current_time: int,
    disrupted_modes: List[str],
) -> Optional[int]:
    """
    Find the next departure time (in minutes from midnight) for a given mode at a station.
    Supports both dynamic/explicit lists of departures and static frequency-based rules.
    """
    base_mode = mode.split("_")[0] if mode.startswith("Bus_") else mode
    if base_mode in disrupted_modes or mode in disrupted_modes:
        return None

    # On-demand modes are always available immediately
    if mode in ("Walk", "Rapido_Bike", "Ola_Auto"):
        return current_time

    schedule = SCHEDULES.get(mode)
    if not schedule:
        return current_time

    # 1. Check if this is a frequency-based schedule config
    if isinstance(schedule, dict) and "frequency" in schedule:
        freq = schedule["frequency"]
        start = schedule["first_departure"]
        end = schedule["last_departure"]
        if current_time < start:
            return start
        if current_time > end:
            return None
        elapsed = current_time - start
        intervals = math.ceil(elapsed / freq)
        next_dep = start + intervals * freq
        return next_dep if next_dep <= end else None

    # 2. Otherwise, treat as explicit station-departure lists
    if isinstance(schedule, dict):
        departures = schedule.get(station, [])
        if not departures:
            departures = schedule.get("_all", [])
            if departures == [0]:
                return current_time
    else:
        departures = []

    for dep in departures:
        if dep >= current_time:
            return dep

    return None


